import{c as a,Q as t,j as i,m as n}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Finance Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/finance/index.md","filePath":"guide/admin/finance/index.md","lastUpdated":1778862269000}'),r={name:"guide/admin/finance/index.md"};function o(s,e,l,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="finance-overview" tabindex="-1">Finance Overview <a class="header-anchor" href="#finance-overview" aria-label="Permalink to &quot;Finance Overview&quot;">​</a></h1><p>The Finance section is where you operate the billing engine — define plans and meters, manage each customer&#39;s billing setup, issue invoices, record payments, and reconcile credits.</p><p>If you have not read <a href="./../../concepts/plans-and-meters">Plans &amp; Meters</a> yet, do that first. The pages below assume you understand meters, plan versions, and the production / non-production distinction.</p><h2 id="what-lives-here" tabindex="-1">What lives here <a class="header-anchor" href="#what-lives-here" aria-label="Permalink to &quot;What lives here&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>What you do here</th></tr></thead><tbody><tr><td><a href="./customer-finance">Customer Finance</a></td><td>The cross-customer billing dashboard — outstanding, overdue, credit exposure, usage overages. Export financial reports.</td></tr><tr><td><a href="./customers">Finance Customers</a></td><td>The list of all customers with billing accounts. Jump to a customer&#39;s full billing view.</td></tr><tr><td><a href="./customer-billing">Customer Billing</a></td><td>One customer&#39;s full billing — invoices, payments, credits, and the Billing Setup tab where you configure plans, tax, and per-tenant overrides.</td></tr><tr><td><a href="./invoices">Invoices</a></td><td>Cross-customer invoice list. Search across customers, periods, statuses.</td></tr><tr><td><a href="./payments">Payments</a></td><td>Cross-customer payment list. Record payments, reconcile, search.</td></tr><tr><td><a href="./plans">Plans</a></td><td>Define plans and their versions. Bind meters with included quantities and overage pricing.</td></tr><tr><td><a href="./meters">Meters</a></td><td>Define meters — what you measure usage in. Built-in and custom.</td></tr><tr><td><a href="./usage">Usage</a></td><td>Query aggregated usage at hourly / daily / monthly granularity, filtered by customer, tenant, env, meter, and date range.</td></tr></tbody></table><h2 id="typical-billing-workflows" tabindex="-1">Typical billing workflows <a class="header-anchor" href="#typical-billing-workflows" aria-label="Permalink to &quot;Typical billing workflows&quot;">​</a></h2><h3 id="onboarding-a-new-customer" tabindex="-1">Onboarding a new customer <a class="header-anchor" href="#onboarding-a-new-customer" aria-label="Permalink to &quot;Onboarding a new customer&quot;">​</a></h3><ol><li>Confirm the customer is on a plan (<a href="./../customers">Customers</a>).</li><li>Open their <strong>Billing Setup</strong> tab on <a href="./customer-billing">Customer Billing</a>. Confirm Plan, Billing Interval, Tax Rate, Payment Mode.</li><li>Configure Production Environments. For non-perpetual plans, configure Non-Production Billing rules.</li><li>Save.</li></ol><h3 id="issuing-a-periodic-invoice" tabindex="-1">Issuing a periodic invoice <a class="header-anchor" href="#issuing-a-periodic-invoice" aria-label="Permalink to &quot;Issuing a periodic invoice&quot;">​</a></h3><ol><li>Open the customer on <a href="./customer-billing">Customer Billing</a>.</li><li>Click <strong>Issue Invoice</strong>. For period-based plans, pick the billing period (start auto-fills). For perpetual plans, enter the amount.</li><li>Click <strong>Issue Invoice</strong> in the modal.</li></ol><h3 id="recording-a-payment" tabindex="-1">Recording a payment <a class="header-anchor" href="#recording-a-payment" aria-label="Permalink to &quot;Recording a payment&quot;">​</a></h3><ol><li>Open the customer on <a href="./customer-billing">Customer Billing</a>.</li><li>Click <strong>Record Payment</strong>.</li><li>Select the invoice, enter the amount and method, add reference if applicable.</li><li>Save.</li></ol><p>The payment also appears in <a href="./payments">Payments</a>.</p><h3 id="reconciling-overage" tabindex="-1">Reconciling overage <a class="header-anchor" href="#reconciling-overage" aria-label="Permalink to &quot;Reconciling overage&quot;">​</a></h3><ol><li>Open <a href="./customer-finance">Customer Finance</a> and toggle <strong>Over Plan</strong>.</li><li>For each customer with an overage, decide: upgrade their plan, contact them, apply a credit, or do nothing (the overage flows into the next invoice automatically).</li></ol>',15)])])}const g=a(r,[["render",o]]);export{m as __pageData,g as default};
